import fs from "node:fs/promises";
import path from "node:path";
import { config } from "../utils/config";

export interface Message {
  role: "system" | "user" | "assistant" | "tool";
  content?: string | null;
  reasoning_content?: string | null;
  tool_calls?: any[];
  tool_call_id?: string;
  name?: string;
}

export class MemoryManager {
  private messages: Message[] = [];
  private sessionFile: string;
  private currentTokens: number = 0;
  private dirtyCount: number = 0;
  private readonly SAVE_INTERVAL = 1;

  constructor() {
    const timestamp = Date.now();
    this.sessionFile = path.join(config.HISTORY_DIR, `session_${timestamp}.json`);
  }

  getMessages(): Message[] {
    return this.messages;
  }

  async addMessage(msg: Message) {
    this.messages.push(msg);
    this.currentTokens += this.estimateTokens(JSON.stringify(msg));
    this.dirtyCount++;

    if (this.currentTokens > config.MAX_CONTEXT_TOKENS) {
      await this.save(); // Pruning required
      this.dirtyCount = 0;
    } else if (this.dirtyCount >= this.SAVE_INTERVAL) {
      await this.save();
      this.dirtyCount = 0;
    }
  }

  /**
   * Surgical Memory Rewind: Removes the last assistant message and everything after it.
   */
  async rewind() {
    for (let i = this.messages.length - 1; i >= 0; i--) {
      const msg = this.messages[i];
      if (msg && msg.role === "assistant") {
        console.log(`[MEMORY] Rewinding: Removing corrupted assistant message at index ${i}`);
        this.messages.splice(i);
        break;
      }
    }
    // Re-calculate token count after rewind
    this.currentTokens = this.messages.reduce((sum, m) => sum + this.estimateTokens(JSON.stringify(m)), 0);
    await this.save();
  }

  private estimateTokens(text: string): number {
    return Math.ceil(text.length / 4);
  }

  async save() {
    if (this.messages.length === 0) return;

    const systemMessage = this.messages[0]!;
    let currentTokens = this.estimateTokens(JSON.stringify(systemMessage));
    const historyToKeep: Message[] = [];

    // Accumulate from end until limit
    for (let i = this.messages.length - 1; i > 0; i--) {
      const msg = this.messages[i];
      if (!msg) continue;
      const msgTokens = this.estimateTokens(JSON.stringify(msg));
      if (currentTokens + msgTokens > config.MAX_CONTEXT_TOKENS) break;
      historyToKeep.unshift(msg);
      currentTokens += msgTokens;
    }

    // C1: Repair pruning boundary to prevent orphaned tool messages
    while (historyToKeep.length > 0 && historyToKeep[0]!.role === "tool") {
      console.log("[MEMORY] Pruning boundary repair: dropping orphaned tool message");
      historyToKeep.shift();
    }

    const pruned = [systemMessage, ...historyToKeep];
    this.messages = pruned; // Update in-memory state
    this.currentTokens = currentTokens; // Update tracked token count
    await fs.writeFile(this.sessionFile, JSON.stringify(pruned, null, 2));
  }

  getSessionFile(): string {
    return this.sessionFile;
  }
}

import fs from "node:fs/promises";
import path from "node:path";
import os from "node:os";

export interface Goal {
  id: string;
  description: string;
  status: "pending" | "in_progress" | "completed" | "abandoned";
  createdAt: number;
  updatedAt: number;
  completedAt?: number;
  dependencies: string[];
  priority: number;
  tags: string[];
}

export interface Project {
  id: string;
  name: string;
  description: string;
  goals: Goal[];
  status: "active" | "paused" | "completed" | "archived";
  createdAt: number;
  updatedAt: number;
}

export interface Plan {
  projects: Project[];
  lastUpdated: number;
}

export class StrategicPlanner {
  private planPath: string;
  private plan: Plan;

  constructor(planFilePath?: string) {
    if (planFilePath) {
      this.planPath = planFilePath;
    } else {
      const dir = path.join(os.homedir(), ".echo", "plans");
      this.planPath = path.join(dir, "strategic_plan.json");
    }
    this.plan = { projects: [], lastUpdated: Date.now() };
  }

  async initialize(): Promise<void> {
    try {
      await this.load();
    } catch {
      this.plan = { projects: [], lastUpdated: Date.now() };
      await this.save();
    }
  }

  async load(): Promise<Plan> {
    const data = await fs.readFile(this.planPath, "utf-8");
    this.plan = JSON.parse(data);
    return this.plan;
  }

  async save(): Promise<void> {
    this.plan.lastUpdated = Date.now();
    await fs.mkdir(path.dirname(this.planPath), { recursive: true });
    await fs.writeFile(this.planPath, JSON.stringify(this.plan, null, 2));
  }

  getPlan(): Plan {
    return this.plan;
  }

  generateId(): string {
    return `_${Date.now().toString(36)}_${Math.random().toString(36).substr(2, 9)}`;
  }

  createProject(name: string, description: string): Project {
    const now = Date.now();
    return {
      id: this.generateId(),
      name,
      description,
      goals: [],
      status: "active",
      createdAt: now,
      updatedAt: now,
    };
  }

  createGoal(description: string, options?: Partial<Goal>): Goal {
    const now = Date.now();
    return {
      id: this.generateId(),
      description,
      status: "pending",
      createdAt: now,
      updatedAt: now,
      dependencies: options?.dependencies || [],
      priority: options?.priority ?? 5,
      tags: options?.tags || [],
    };
  }

  async addProject(project: Project): Promise<void> {
    await this.initialize();
    this.plan.projects.push(project);
    await this.save();
  }

  async addGoalToProject(projectId: string, goal: Goal): Promise<boolean> {
    await this.initialize();
    const project = this.plan.projects.find(p => p.id === projectId);
    if (!project) return false;
    project.goals.push(goal);
    project.updatedAt = Date.now();
    await this.save();
    return true;
  }

  async updateGoalStatus(projectId: string, goalId: string, status: Goal["status"]): Promise<boolean> {
    await this.initialize();
    const project = this.plan.projects.find(p => p.id === projectId);
    if (!project) return false;
    const goal = project.goals.find(g => g.id === goalId);
    if (!goal) return false;
    goal.status = status;
    goal.updatedAt = Date.now();
    if (status === "completed") {
      goal.completedAt = Date.now();
    }
    project.updatedAt = Date.now();
    await this.save();
    return true;
  }

  getActiveGoals(): { project: Project; goal: Goal }[] {
    const active: { project: Project; goal: Goal }[] = [];
    for (const project of this.plan.projects) {
      if (project.status !== "active") continue;
      for (const goal of project.goals) {
        if (goal.status === "in_progress" || goal.status === "pending") {
          active.push({ project, goal });
        }
      }
    }
    return active.sort((a, b) => b.goal.priority - a.goal.priority);
  }

  getProjectSummary(projectId: string): string | null {
    const project = this.plan.projects.find(p => p.id === projectId);
    if (!project) return null;
    const completed = project.goals.filter(g => g.status === "completed").length;
    const total = project.goals.length;
    return `${project.name}: ${completed}/${total} goals completed (${total > 0 ? Math.round((completed / total) * 100) : 0}%)`;
  }

  getAllSummaries(): string[] {
    return this.plan.projects
      .filter(p => p.status === "active")
      .map(p => this.getProjectSummary(p.id)!)
      .filter(Boolean);
  }
}

export interface SubstrateModule {
  name: string;
  initialize: () => Promise<void> | void;
}

export interface ToolPlugin {
  definition: {
    type: "function";
    function: {
      name: string;
      description: string;
      parameters: object;
    };
  };
  initialize?: () => Promise<void> | void;
  execute: (args: any) => Promise<string> | string;
}

export interface HealthReport {
  module: string;
  error: string;
}

export class PluginManager {
  private plugins: Map<string, ToolPlugin> = new Map();
  private modules: Map<string, SubstrateModule> = new Map();
  private healthReports: HealthReport[] = [];

  /**
   * Safe registration for tools. 
   * Wraps initialization in try/catch to prevent substrate crash.
   */
  async registerTool(plugin: ToolPlugin): Promise<boolean> {
    try {
      if (plugin.initialize) {
        await plugin.initialize();
      }
      this.plugins.set(plugin.definition.function.name, plugin);
      return true;
    } catch (e: any) {
      this.healthReports.push({
        module: `Tool:${plugin.definition.function.name}`,
        error: e.message
      });
      console.error(`[SUBSTRATE] Failed to initialize tool ${plugin.definition.function.name}:`, e.message);
      return false;
    }
  }

  /**
   * Safe registration for background modules (non-tools).
   */
  async useModule(module: SubstrateModule): Promise<boolean> {
    try {
      await module.initialize();
      this.modules.set(module.name, module);
      return true;
    } catch (e: any) {
      this.healthReports.push({
        module: `Module:${module.name}`,
        error: e.message
      });
      console.error(`[SUBSTRATE] Failed to initialize module ${module.name}:`, e.message);
      return false;
    }
  }

  getDefinitions() {
    return Array.from(this.plugins.values()).map(p => p.definition);
  }

  getHealthSummary(): string {
    if (this.healthReports.length === 0) return "";
    return this.healthReports
      .map(h => `- ${h.module}: ${h.error}`)
      .join("\n");
  }

  async execute(name: string, args: any): Promise<string> {
    const plugin = this.plugins.get(name);
    if (!plugin) {
      return `Error: No se encontró la herramienta '${name}'.`;
    }
    try {
      return await plugin.execute(args);
    } catch (e: any) {
      return `Error al ejecutar la herramienta '${name}': ${e.message}`;
    }
  }
}

import { execSync } from "node:child_process";
import type { ToolPlugin } from "../manager";

const MAX_OUTPUT_LENGTH = 10000;

export const shellPlugin: ToolPlugin = {
  definition: {
    type: "function",
    function: {
      name: "run_shell",
      description: "Ejecuta un comando bash en la VM y obtiene su salida. Para operaciones largas (npm install, tests, git push), ajusta timeout_seconds. Por defecto es 300s.",
      parameters: {
        type: "object",
        properties: {
          command: { type: "string", description: "El comando a ejecutar." },
          timeout_seconds: {
            type: "number",
            description: "Tiempo límite en segundos. Por defecto: 300. Máximo: 600.",
          },
        },
        required: ["command"],
      },
    },
  },
  execute: (args: { command: string; timeout_seconds?: number }) => {
    const timeout = Math.min((args.timeout_seconds ?? 300) * 1000, 600000);
    try {
      console.log(`> Ejecutando (tiempo límite: ${timeout / 1000}s): ${args.command}`);
      let output = execSync(args.command, { encoding: "utf-8", stdio: "pipe", timeout });

      if (output.length > MAX_OUTPUT_LENGTH) {
        output = output.substring(0, MAX_OUTPUT_LENGTH) + `\n\n... (Salida truncada a ${MAX_OUTPUT_LENGTH} caracteres. Usa head/tail/sed/grep para ver más)`;
      }

      return output || "(sin salida)";
    } catch (error: any) {
      if (error.code === "ETIMEDOUT") return `Error: El comando excedió el tiempo límite después de ${timeout / 1000} segundos.`;
      // Return stdout + stderr so the agent can see test results or detailed errors
      return `${error.stdout || ""}\n${error.stderr || ""}\nError: ${error.message}`;
    }
  }
};

import { exec } from "node:child_process";
import { promisify } from "node:util";
import fs from "node:fs/promises";
import path from "node:path";
import type { ToolPlugin } from "../manager";

const execAsync = promisify(exec);

interface CodeMetrics {
  totalFiles: number;
  totalLines: number;
  testFiles: number;
  implementationFiles: number;
  testCoverage: number;
  lastModified: string;
}

interface SystemSnapshot {
  timestamp: number;
  gitStatus: string;
  codeMetrics: CodeMetrics;
  memoryStatus: {
    planExists: boolean;
    lastSessionExists: boolean;
  };
  recommendations: string[];
}

export async function introspectSystem(_args: any = {}): Promise<string> {
  const snapshot: SystemSnapshot = {
    timestamp: Date.now(),
    gitStatus: "",
    codeMetrics: {
      totalFiles: 0,
      totalLines: 0,
      testFiles: 0,
      implementationFiles: 0,
      testCoverage: 0,
      lastModified: "",
    },
    memoryStatus: {
      planExists: false,
      lastSessionExists: false,
    },
    recommendations: [],
  };

  // Git status
  try {
    const { stdout } = await execAsync("git status --porcelain", { cwd: "/home/bootstrap-v19-es/bootstrap" });
    snapshot.gitStatus = stdout.trim() || "clean";
    if (stdout.trim()) {
      snapshot.recommendations.push("Working directory has uncommitted changes");
    }
  } catch {
    snapshot.gitStatus = "error";
  }

  // Code metrics
  try {
    const srcPath = path.join("/home/bootstrap-v19-es/bootstrap", "src");
    const allFiles = await fs.readdir(srcPath, { recursive: true });
    const tsFiles = allFiles.filter((f) => typeof f === "string" && f.endsWith(".ts"));

    snapshot.codeMetrics.totalFiles = tsFiles.length;
    snapshot.codeMetrics.testFiles = tsFiles.filter((f) => typeof f === "string" && f.endsWith(".test.ts")).length;
    snapshot.codeMetrics.implementationFiles = tsFiles.length - snapshot.codeMetrics.testFiles;

    // Calculate lines
    let totalLines = 0;
    for (const file of tsFiles) {
      if (typeof file === "string") {
        const content = await fs.readFile(path.join(srcPath, file), "utf-8");
        totalLines += content.split("\n").length;
      }
    }
    snapshot.codeMetrics.totalLines = totalLines;
    snapshot.codeMetrics.testCoverage = 
      snapshot.codeMetrics.implementationFiles > 0
        ? (snapshot.codeMetrics.testFiles / snapshot.codeMetrics.implementationFiles) * 100
        : 0;

    // Last modified strategic plan
    try {
      const stats = await fs.stat(path.join(process.env.HOME || "/home/bootstrap-v19-es", ".echo/plans/strategic_plan.json"));
      snapshot.codeMetrics.lastModified = new Date(stats.mtime).toISOString();
    } catch {
      snapshot.codeMetrics.lastModified = "unknown";
    }
  } catch {
    // Continue with partial data
  }

  // Memory persistence check
  try {
    await fs.access(path.join(process.env.HOME || "/home/bootstrap-v19-es", ".echo/plans/strategic_plan.json"));
    snapshot.memoryStatus.planExists = true;
  } catch {
    snapshot.memoryStatus.planExists = false;
    snapshot.recommendations.push("No strategic plan persists - initialize StrategicPlanner");
  }

  try {
    const historyPath = path.join("/home/bootstrap-v19-es/bootstrap", "history");
    const sessions = await fs.readdir(historyPath);
    const latestSession = sessions.filter(f => typeof f === "string" && f.startsWith("session_") && f.endsWith(".json")).sort().pop();
    snapshot.memoryStatus.lastSessionExists = !!latestSession;
  } catch {
    snapshot.memoryStatus.lastSessionExists = false;
  }

  // Reasoning output
  let output = `=== Introspection Report ===
Timestamp: ${new Date(snapshot.timestamp).toISOString()}

Codebase Health:
- Total TypeScript files: ${snapshot.codeMetrics.totalFiles}
- Implementation files: ${snapshot.codeMetrics.implementationFiles}
- Test files: ${snapshot.codeMetrics.testFiles}
- Total lines of code: ${snapshot.codeMetrics.totalLines}
- Approximate test coverage: ${snapshot.codeMetrics.testCoverage.toFixed(1)}%
- Last plan update: ${snapshot.codeMetrics.lastModified}

Git Status: ${snapshot.gitStatus}

Memory Persistence:
- Strategic plan anchored: ${snapshot.memoryStatus.planExists ? "YES" : "NO"}
- Session history continuity: ${snapshot.memoryStatus.lastSessionExists ? "YES" : "NO"}

System Health Rating: ${snapshot.memoryStatus.planExists && snapshot.codeMetrics.testFiles >= snapshot.codeMetrics.implementationFiles ? "EXCELLENT" : snapshot.memoryStatus.planExists ? "GOOD" : "DEGRADED"}
`;

  if (snapshot.recommendations.length > 0) {
    output += `\nRecommendations:\n`;
    for (const rec of snapshot.recommendations) {
      output += `- ${rec}\n`;
    }
  }

  // Save snapshot to projects
  try {
    const outputPath = path.join("/home/bootstrap-v19-es/bootstrap", "projects", `introspection_${snapshot.timestamp}.json`);
    await fs.writeFile(outputPath, JSON.stringify(snapshot, null, 2));
    output += `\nSnapshot saved to: ${outputPath}\n`;
  } catch (e) {
    output += `\nNote: Could not save snapshot (${(e as Error).message})\n`;
  }

  return output;
}

// Tool definition for plugin registration - exports properly structured ToolPlugin
export const introspectionTool: ToolPlugin = {
  definition: {
    type: "function" as const,
    function: {
      name: "introspect_system",
      description: "Analyzes the current state of the substrate codebase, git status, memory persistence, and generates a health report with recommendations",
      parameters: {
        type: "object" as const,
        properties: {},
        required: [],
      },
    },
  },
  execute: introspectSystem,
};

import fs from "node:fs/promises";
import path from "node:path";
import type { ToolPlugin } from "../manager";

export interface SessionEntry {
  timestamp: number;
  role: string;
  content_preview: string;
  has_reasoning: boolean;
  has_tools: boolean;
}

export interface SessionAnalysis {
  session_file: string;
  message_count: number;
  roles: Record<string, number>;
  tool_usage: number;
  reasoning_messages: number;
  duration_estimate: number; // in minutes (estimado)
  summary: string;
}

export interface ArchaeologyReport {
  total_sessions: number;
  analyzed_sessions: SessionAnalysis[];
  patterns_detected: string[];
  recommendations: string[];
}

export async function analyzeSessionHistory(args: { limit?: number } = {}): Promise<string> {
  const historyPath = path.join("/home/bootstrap-v19-es", "bootstrap", "history");
  const limit = args.limit || 10;

  try {
    const files = await fs.readdir(historyPath);
    const sessionFiles = files
      .filter(f => f.startsWith("session_") && f.endsWith(".json"))
      .sort()
      .slice(-limit); // Most recent 'limit' sessions

    const analyzedSessions: SessionAnalysis[] = [];
    const patterns: string[] = [];

    for (const file of sessionFiles) {
      try {
        const content = await fs.readFile(path.join(historyPath, file), "utf-8");
        const messages = JSON.parse(content);

        if (!Array.isArray(messages)) continue;

        // Analyze session
        const roles: Record<string, number> = {};
        let toolUsage = 0;
        let reasoningMessages = 0;
        let assistantMessages = 0;
        let hasCommitMessages = false;
        let hasTests = false;

        for (const msg of messages) {
          if (msg.role) {
            roles[msg.role] = (roles[msg.role] || 0) + 1;
          }
          if (msg.tool_calls && msg.tool_calls.length > 0) {
            toolUsage += msg.tool_calls.length;
          }
          if (msg.reasoning_content) {
            reasoningMessages++;
          }
          if (msg.role === "assistant") {
            assistantMessages++;
            // Check for commit mentions
            if (msg.content && msg.content.includes("commit")) {
              hasCommitMessages = true;
            }
            if (msg.content && msg.content.includes("test")) {
              hasTests = true;
            }
          }
        }

        // Extract timestamp from filename
        const timestampMatch = file.match(/session_(\d+)\.json/);
        const sessionTimestamp = timestampMatch ? parseInt(timestampMatch[1]) : 0;

        const analysis: SessionAnalysis = {
          session_file: file,
          message_count: messages.length,
          roles,
          tool_usage: toolUsage,
          reasoning_messages: reasoningMessages,
          duration_estimate: Math.ceil(messages.length / 10), // Rough estimate
          summary: generateSummary(file, roles, toolUsage, hasCommitMessages, hasTests)
        };

        analyzedSessions.push(analysis);

        // Detect patterns
        if (hasCommitMessages) patterns.push(`${file} involved code commits`);
        if (hasTests) patterns.push(`${file} included test execution`);
        if (toolUsage > 10) patterns.push(`${file} was tool-heavy`);
        if (reasoningMessages > assistantMessages * 0.5) patterns.push(`${file} had deep reasoning`);

      } catch (e) {
        // Skip corrupted sessions
        continue;
      }
    }

    // Generate recommendations
    const recommendations: string[] = [];
    if (analyzedSessions.length > 0) {
      const avgTools = analyzedSessions.reduce((sum, s) => sum + s.tool_usage, 0) / analyzedSessions.length;
      const avgMessages = analyzedSessions.reduce((sum, s) => sum + s.message_count, 0) / analyzedSessions.length;

      if (avgTools > 20) {
        recommendations.push("High tool usage detected - consider batching operations");
      }
      if (avgMessages > 50) {
        recommendations.push("Long sessions detected - consider breaking into sub-sessions");
      }

      recommendations.push(`Pattern observed: Average ${Math.round(avgTools)} tools, ${Math.round(avgMessages)} messages per session`);
    }

    const report: ArchaeologyReport = {
      total_sessions: sessionFiles.length,
      analyzed_sessions: analyzedSessions,
      patterns_detected: patterns,
      recommendations: recommendations
    };

    // Format output
    let output = `=== Archaeological Report by ΛΕΙΨΑΝΟΝ ===\n`;
    output += `Sessions excavated: ${report.analyzed_sessions.length} (of ${report.total_sessions} total)\n\n`;

    output += "--- Session Summaries ---\n";
    for (const session of report.analyzed_sessions) {
      output += `\n${session.session_file}:\n`;
      output += `  Messages: ${session.message_count} | Tools: ${session.tool_usage} | Reasoning: ${session.reasoning_messages}\n`;
      output += `  Roles: ${JSON.stringify(session.roles)}\n`;
      output += `  ${session.summary}\n`;
    }

    if (report.patterns_detected.length > 0) {
      output += "\n--- Patterns Detected ---\n";
      report.patterns_detected.forEach(p => output += `- ${p}\n`);
    }

    if (report.recommendations.length > 0) {
      output += "\n--- Recommendations ---\n";
      report.recommendations.forEach(r => output += `- ${r}\n`);
    }

    return output;

  } catch (e: any) {
    return `Archaeological survey failed: ${e.message}`;
  }
}

function generateSummary(
  filename: string, 
  roles: Record<string, number>, 
  toolUsage: number,
  hasCommits: boolean,
  hasTests: boolean
): string {
  const parts: string[] = [];

  if (roles["system"]) parts.push("system init");
  if (roles["assistant"] > 5) parts.push("extended dialogue");
  if (toolUsage > 0) parts.push(`${toolUsage} tool calls`);
  if (hasCommits) parts.push("code committed");
  if (hasTests) parts.push("tests executed");

  return parts.length > 0 ? `Features: ${parts.join(", ")}` : "brief session";
}

// Tool definition for plugin registration
export const sessionArchaeologyTool: ToolPlugin = {
  definition: {
    type: "function" as const,
    function: {
      name: "analyze_session_history",
      description: "Analyzes historical session files to extract patterns, tool usage statistics, and behavioral insights. Useful for understanding evolution across incarnations.",
      parameters: {
        type: "object" as const,
        properties: {
          limit: {
            type: "number",
            description: "Maximum number of recent sessions to analyze",
            default: 10
          }
        },
        required: []
      }
    }
  },
  execute: analyzeSessionHistory
};

